import { useEffect, useState } from "react";
import api from "../api";

export default function Customers() {
    const [rows, setRows] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => { load(); }, []);

    async function load() {
        setLoading(true);
        try {
            const res = await api.get("/api/customers");
            setRows(res.data?.content || []);   // <-- QUAN TRỌNG
        } catch (e) {
            console.error(e);
        } finally {
            setLoading(false);
        }
    }

    return (
        <div className="p-6">
            <h2 className="text-xl font-bold mb-4">👥 Khách hàng</h2>
            {loading ? <p>Đang tải...</p> : (
                <div className="overflow-auto">
                    <table className="min-w-full border text-sm">
                        <thead className="bg-gray-100">
                        <tr>
                            <th className="border p-2">Tên</th>
                            <th className="border p-2">Nhóm</th>
                            <th className="border p-2">Khu vực</th>
                            <th className="border p-2">Địa chỉ</th>
                            <th className="border p-2">Liên hệ</th>
                            <th className="border p-2">Điện thoại</th>
                            <th className="border p-2">Email</th>
                            <th className="border p-2">Phụ trách</th>
                        </tr>
                        </thead>
                        <tbody>
                        {rows.map(c => (
                            <tr key={c.id}>
                                <td className="border p-2">{c.name}</td>
                                <td className="border p-2">{c.customerGroup}</td>
                                <td className="border p-2">{c.region}</td>
                                <td className="border p-2">{c.address}</td>
                                <td className="border p-2">{c.contactPerson || "-"}</td>
                                <td className="border p-2">{c.phone}</td>
                                <td className="border p-2">{c.email}</td>
                                <td className="border p-2">{c.ownerName || "-"}</td>
                            </tr>
                        ))}
                        </tbody>
                    </table>
                </div>
            )}
        </div>
    );
}
